#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAXN 100000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, k, b;
        scanf("%d %d %d", &N, &k, &b);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int dp[N];
        int maxLen = 0;
        for (int i = 0; i < N; i++) {
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (A[i] >= k * A[j] + b) {
                    dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
                }
            }
            maxLen = (maxLen > dp[i]) ? maxLen : dp[i];
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

