    let maxLen = 0;
    for (let j = 0; j < N; j++) {
        for (let l = 0; l < j; l++) {
            if (A[j] >= k * A[l] + b) {
                dp[j] = Math.max(dp[j], dp[l] + 1);
            }
        }
        maxLen = Math.max(maxLen, dp[j]);
    }
    console.log(maxLen);
